ground.cypher:
MATCH `(e1:Entity {name: 'ANTAM ENTERPRISES N.V.', type: 'LIMITED LIABILITY COMPANY'})-(r1:*)-(e2:Entity),
      (e2)-(r2:*)-(e3:Other {jurisdiction: 'AW'}), (e2)-(r3:*)-(o1:Officer),
      (e2)-(r4:*)-(a1:Address {countries: 'Bermuda;Isle of Man'}) WHERE NOT EXISTS {(e1)-[:same_as]->(e2)} OR NOT EXISTS {(e1)-[:same_company_as]->(e2)}
RETURN e1, r1.link, e2, r2.link, e3, r3.link, o1, r4.link, a1;
